                min_x3 = max(0, (ai - c1 - 2*c2 + 2) // 3)
                for x3 in range(min_x3, min_x3 + 4):
                    r = ai - 3 * x3
                    if r < 0:
                        break
                    if r > c1 + 2 * c2:
                        continue
                    x2 = max(0, (r - c1 + 1) // 2)
